import React, { useEffect, useState } from "react";

import {
  getGoals,
  createGoal,
  deleteGoal,
} from "../api/goals";

import "../styles/Layouts.css";

function Goals() {

  const [goals, setGoals] =
    useState([]);

  const [goal_name, setGoalName] =
    useState("");

  const [target_amount,
    setTargetAmount] = useState("");

  const loadGoals = async () => {
    try {
      const res = await getGoals();
      setGoals(res.data);
    } catch {
      alert("Không tải được mục tiêu!");
    }
  };

  useEffect(() => {
    loadGoals();
  }, []);

  const handleCreate = async () => {
    try {

      await createGoal({
        goal_name,
        target_amount,
      });

      setGoalName("");
      setTargetAmount("");

      loadGoals();

    } catch (err) {
      alert(
        err?.response?.data?.message
      );
    }
  };

  const handleDelete = async (id) => {
    try {
      await deleteGoal(id);
      loadGoals();
    } catch (err) {
      alert(
        err?.response?.data?.message
      );
    }
  };

  return (
    <div className="main-content">

      <div className="page-header">
        <h1 className="page-title">
          Mục tiêu tài chính
        </h1>
      </div>

      <div className="card">

        <input
          type="text"
          placeholder="Tên mục tiêu"
          value={goal_name}
          onChange={(e) =>
            setGoalName(
              e.target.value
            )
          }
        />

        <br />
        <br />

        <input
          type="number"
          placeholder="Mục tiêu"
          value={target_amount}
          onChange={(e) =>
            setTargetAmount(
              e.target.value
            )
          }
        />

        <br />
        <br />

        <button
          className="btn btn-primary"
          onClick={handleCreate}
        >
          Tạo mục tiêu
        </button>

      </div>

      <div className="grid-3">

        {goals.map((g) => (

          <div
            key={g.goal_id}
            className="stat-card"
          >

            <h3>
              {g.goal_name}
            </h3>

            <p>
              Hiện tại:
              {" "}
              {Number(
                g.current_amount || 0
              ).toLocaleString()}
            </p>

            <p>
              Mục tiêu:
              {" "}
              {Number(
                g.target_amount || 0
              ).toLocaleString()}
            </p>

            <button
              className="btn btn-danger"
              onClick={() =>
                handleDelete(
                  g.goal_id
                )
              }
            >
              Xóa
            </button>

          </div>

        ))}

      </div>

    </div>
  );
}

export default Goals;
